using Ledgerly.Application.Bills; using Microsoft.AspNetCore.Mvc; namespace Ledgerly.Api.Controllers; [ApiController][Route("api/organizations/{organizationId:guid}/bills")] public sealed class BillsController:ControllerBase{ private readonly BillService _s; public BillsController(BillService s)=>_s=s; [HttpGet("{billId:guid}")] public async Task<IActionResult> Get(Guid organizationId,Guid billId,CancellationToken ct=default){var r=await _s.GetByIdAsync(organizationId,billId,ct);return r.IsFailure?NotFound(new{error=r.Error}):Ok(r.Value);} [HttpPost] public async Task<IActionResult> Create(Guid organizationId,[FromBody]CreateBillRequest req,CancellationToken ct=default){var r=await _s.CreateAsync(req,ct);return r.IsFailure?BadRequest(new{error=r.Error}):Ok(r.Value);} [HttpPost("{billId:guid}/lines")] public async Task<IActionResult> AddLine(Guid organizationId,Guid billId,[FromBody]AddBillLineRequest req,CancellationToken ct=default){var r=await _s.AddLineAsync(organizationId,billId,req,ct);return r.IsFailure?BadRequest(new{error=r.Error}):Ok(r.Value);} [HttpPost("{billId:guid}/approve")] public async Task<IActionResult> Approve(Guid organizationId,Guid billId,CancellationToken ct=default){var r=await _s.ApproveAsync(organizationId,billId,ct);return r.IsFailure?BadRequest(new{error=r.Error}):Ok(r.Value);} [HttpPost("{billId:guid}/payments")] public async Task<IActionResult> Pay(Guid organizationId,Guid billId,[FromBody]RecordBillPaymentRequest req,CancellationToken ct=default){var r=await _s.RecordPaymentAsync(organizationId,billId,req,ct);return r.IsFailure?BadRequest(new{error=r.Error}):Ok(r.Value);} }
